int main() {
    int n;
    cin >> n;
    pen.c(5);
    for (int i = 1; i <= n; i++) {
        pen.fd(100).rt(120);
        pen.fd(100).rt(120);
        pen.fd(100).rt(120);
        pen.rt(360.0 / n);
    }
    pen.c(13).o(110).oo(20);
    return 0;
}
